SELECT id, check_no, check_date, maker, check_status, remark, created_at, updated_at, deleted FROM clinic_inventory_check WHERE deleted = 0
AND (check_no LIKE CONCAT('%', #{keyword}, '%') OR maker LIKE CONCAT('%', #{keyword}, '%') OR check_status LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_inventory_check
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
